489→func (e *DurationExpr) PositionRange() posrange.PositionRange {
490→	if e.Op == STEP || e.Op == RANGE {
491→		return posrange.PositionRange{
492→			Start: e.StartPos,
493→			End:   e.EndPos,
494→		}
495→	}
496→	if e.RHS == nil {
497→		return posrange.PositionRange{
498→			Start: e.StartPos,
499→			End:   e.RHS.PositionRange().End,
500→		}
501→	}
502→	if e.LHS == nil {
503→		return posrange.PositionRange{
504→			Start: e.StartPos,
505→			End:   e.RHS.PositionRange().End,
506→		}
507→	}
508→	return mergeRanges(e.LHS, e.RHS)
509→}
