268→// ContainsSameLabelset checks if a vector has samples with the same labelset
269→// Such a behavior is semantically undefined
270→// https://github.com/prometheus/prometheus/issues/4562
271→func (vec Vector) ContainsSameLabelset() bool {
272→	switch len(vec) {
273→	case 0, 1:
